-- 현재 설정 확인
SELECT TABLESPACE_NAME, CONTENTS, RETENTION, BIGFILE,
       STATUS
FROM DBA_TABLESPACES
WHERE CONTENTS = 'UNDO';

-- RETENTION GUARANTEE 활성화
-- ALTER TABLESPACE undotbs1 RETENTION GUARANTEE;

-- RETENTION NOGUARANTEE로 복원
-- ALTER TABLESPACE undotbs1 RETENTION NOGUARANTEE;

-- 기존 데이터 파일 크기 확장
ALTER DATABASE DATAFILE '/u01/app/oracle/oradata/orcl/undotbs01.dbf' RESIZE 4G;

-- 새 데이터 파일 추가 (AUTOEXTEND ON)
ALTER TABLESPACE undotbs1 
ADD DATAFILE '/u01/app/oracle/oradata/orcl/undotbs02.dbf' 
SIZE 2G AUTOEXTEND ON NEXT 256M MAXSIZE 8G;

-- AUTOEXTEND 설정 변경
ALTER DATABASE DATAFILE '/u01/app/oracle/oradata/orcl/undotbs01.dbf'
AUTOEXTEND ON NEXT 256M MAXSIZE 8G;
